#include <stdio.h> // Required for scanf and printf

int main() {
    // Declare integer variables for length and width in cm
    int length_cm;
    int width_cm;

    // Declare integer variables for calculated area and perimeter in cm
    int area_cm2;
    int perimeter_cm;

    // Declare a double variable for area in square meters for precision
    double area_m2;

    // Read length and width from standard input
    scanf("%d", &length_cm);
    scanf("%d", &width_cm);

    // Calculate area in square centimeters using multiplication operator
    area_cm2 = length_cm * width_cm;

    // Calculate perimeter in centimeters using addition and multiplication operators
    perimeter_cm = 2 * (length_cm + width_cm);

    // Convert area from square centimeters to square meters
    // Cast area_cm2 to double to ensure floating-point division
    // Use 10000.0 (a double literal) to further guarantee floating-point arithmetic
    area_m2 = (double)area_cm2 / 10000.0;

    // Print the results to standard output, each on a new line
    printf("Length: %d cm\n", length_cm);
    printf("Width: %d cm\n", width_cm);
    printf("Area: %d sq cm\n", area_cm2);
    printf("Perimeter: %d cm\n", perimeter_cm);
    // Print area_m2 with exactly four decimal places using "%.4f" format specifier
    printf("Area (sq meters): %.4f sq m\n", area_m2);

    return 0; // Indicate successful program execution
}
